import{_ as a,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const g=JSON.parse('{"title":"Школа № 36","description":"Школа, связанная с юностью Владимира Шахрина, Олега Решетникова и ранней историей группы «Чайф».","frontmatter":{"title":"Школа № 36","description":"Школа, связанная с юностью Владимира Шахрина, Олега Решетникова и ранней историей группы «Чайф».","outline":"deep"},"headers":[],"relativePath":"places/school-36.md","filePath":"places/school-36.md"}'),o={name:"places/school-36.md"};function s(n,t,d,i,h,p){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="школа-no-36" tabindex="-1">Школа № 36 <a class="header-anchor" href="#школа-no-36" aria-label="Permalink to “Школа № 36”">​</a></h1><p><strong>Школа № 36</strong> — одно из неожиданных, но важных мест на карте уральского рока. Именно здесь, в стенах обычной свердловской школы, началась история дружбы и первых музыкальных опытов будущих участников группы <strong>«Чайф»</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Малышева, 134</li><li><strong>Период ключевого значения:</strong> конец 1970-х — начало 1980-х годов</li><li><strong>Главная роль:</strong> место юности и первых музыкальных опытов основателей «Чайфа»</li><li><strong>Связанные группы:</strong> «Чайф»</li><li><strong>Статус сегодня:</strong> действующая школа</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Школа № 36 важна как место, где история уральского рока начинается не с большой сцены и не с официального клуба, а с обычной школьной среды. Здесь будущие участники <strong>«Чайфа»</strong> дружили, слушали западную музыку, учились играть на гитарах и делали первые попытки сочинять собственные песни.</p><p>Для истории группы это место ценно тем, что именно здесь сформировалась ранняя человеческая и музыкальная связь между Владимиром Шахриным и Олегом Решетниковым. Позже к ним присоединился Владимир Бегунов, и постепенно начал складываться костяк будущего коллектива.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Средняя общеобразовательная школа № 36 стала одним из первых важных мест в биографии группы <strong>«Чайф»</strong>. В конце 1970-х — начале 1980-х годов здесь учились будущие основатели коллектива — Владимир Шахрин и Олег Решетников.</p><p>Они сидели за одной партой, дружили, слушали западную рок-музыку и начинали играть на гитарах. Среди музыкальных ориентиров того времени в материалах проекта упоминаются <strong>The Beatles</strong>, <strong>The Rolling Stones</strong> и <strong>Deep Purple</strong>. Для школьников это была не просто музыка, а способ почувствовать себя частью более широкой культуры, отличной от официальной советской повседневности.</p><p>Первые аккорды, первые песни и первые попытки сочинять происходили прямо в школьной жизни: на переменах, после уроков, на вечерах и в общении с одноклассниками. По воспоминаниям Владимира Шахрина, именно в школе № 36 он понял, что музыка станет важной частью его жизни.</p><p>Вместе с Олегом Решетниковым они давали первые неформальные «концерты» для одноклассников, играли на школьных вечерах и постепенно находили единомышленников. Позже к ним присоединился Владимир Бегунов — так начал формироваться костяк будущей группы <strong>«Чайф»</strong>.</p><p>Школа стала не только местом дружбы и первых музыкальных опытов, но и пространством, где складывался ранний характер будущего коллектива: искренний, дворовый, ироничный и очень городской. Многие черты «чайфовского» стиля можно связать именно с этой атмосферой — школьными коридорами, дружескими разговорами, юношеским максимализмом и любовью к своему городу.</p><p>В 1985 году группа <strong>«Чайф»</strong> официально заявила о себе, но школа № 36 осталась в истории как одна из точек её рождения.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Малышева, 134.</p><p>Школа находится в Екатеринбурге и может быть включена в тематический маршрут по местам, связанным с группой <strong>«Чайф»</strong>.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/vladimir-shahrin.html">Владимир Шахрин</a></td><td>Лидер «Чайфа», учился здесь</td></tr><tr><td><a href="/Knowledge-Base/people/oleg-reshetnikov.html">Олег Решетников</a></td><td>Сооснователь группы, одноклассник Владимира Шахрина</td></tr><tr><td><a href="/Knowledge-Base/people/vladimir-begunov.html">Владимир Бегунов</a></td><td>Присоединился позже, связан со школой через общих друзей</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/chaif.html">Чайф</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня школа № 36 продолжает работать как действующее образовательное учреждение. В ней учатся дети, проходят уроки и школьные мероприятия.</p><p>Здание не имеет специальных памятных знаков, но среди учителей, учеников и поклонников уральского рока сохраняется память о его связи с историей <strong>«Чайфа»</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Это действующая школа, поэтому доступ внутрь ограничен. Для маршрута по рок-местам здание лучше рассматривать как внешнюю точку с историческим комментарием. При посещении важно не мешать учебному процессу.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока школа № 36 планируется как одна из точек маршрутов, посвящённых группе <strong>«Чайф»</strong> и ранней истории свердловского рока.</p><p>В материалах проекта указана планируемая установка памятной доски на фасаде школы. Также возможны экскурсии и уроки краеведения для школьников, где будет рассказано о том, как обычная школа стала частью истории одной из главных групп уральского рока.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Планируемая установка памятной доски на фасаде школы</td></tr><tr><td>2026 год</td><td>Экскурсии и уроки краеведения о связи школы с историей «Чайфа»</td></tr><tr><td>2026 год</td><td>Возможный концерт с участием молодых музыкантов в актовом зале школы</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Школу № 36 удобно включать в маршрут по местам, связанным с группой <strong>«Чайф»</strong>. Её можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-mzhk-molodezhny.html">ДК МЖК / Центр культуры «Молодёжный»</a></li><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li></ul>',32)])])}const b=a(o,[["render",s]]);export{g as __pageData,b as default};
